const jwt = require('jsonwebtoken');

const JWT_SECRET = process.env.JWT_SECRET || (() => {
  throw new Error('JWT_SECRET environment variable is required');
})();

const ALLOWED_ALGORITHMS = ['HS256', 'HS384', 'HS512'];

const jwtVerifyMiddleware = (req, res, next) => {
  try {
    const authHeader = req.headers.authorization;
    
    if (!authHeader) {
      return res.status(401).json({ error: 'Authorization header missing' });
    }

    const parts = authHeader.split(' ');
    
    if (parts.length !== 2 || parts[0] !== 'Bearer') {
      return res.status(401).json({ error: 'Invalid authorization header format. Expected: Bearer <token>' });
    }

    const token = parts[1];

    if (!token) {
      return res.status(401).json({ error: 'Token missing' });
    }

    const decoded = jwt.verify(token, JWT_SECRET, {
      algorithms: ALLOWED_ALGORITHMS,
      complete: false,
      clockTolerance: 0,
      ignoreExpiration: false,
      ignoreNotBefore: false
    });

    if (!decoded.exp) {
      return res.status(401).json({ error: 'Token must have an expiration claim' });
    }

    if (!decoded.sub && !decoded.userId) {
      return res.status(401).json({ error: 'Token must contain user identification (sub or userId)' });
    }

    req.user = {
      id: decoded.sub || decoded.userId,
      email: decoded.email,
      role: decoded.role,
      ...decoded
    };

    next();
  } catch (error) {
    if (error.name === 'TokenExpiredError') {
      return res.status(401).json({ error: 'Token has expired' });
    }
    
    if (error.name === 'JsonWebTokenError') {
      return res.status(401).json({ error: 'Invalid token' });
    }
    
    if (error.name === 'NotBeforeError') {
      return res.status(401).json({ error: 'Token not yet valid' });
    }

    return res.status(500).json({ error: 'Token verification failed' });
  }
};

module.exports = jwtVerifyMiddleware;